def min_squares(width, height):
    if width == 0 or height == 0:
        return 0

    count = 0
    while width != 0 and height != 0:
        if width == height:
            count += 1
            break
        elif width > height:
            count += width // height
            width %= height
        else: # height > width
            count += height // width
            height %= width

    return count
